final:
module RefModule(
    input               clk     ,   
    input               rst     ,
    input               en      ,
    output  reg [4:0]   lfsr_out
);

wire feedback;

wire __feedback_tmp = lfsr_out[4] ^ lfsr_out[2];
assign feedback = __feedback_tmp;

always @(posedge clk) begin
    if (rst)
        lfsr_out <= 5'b00001;
    else if (en)
        lfsr_out <= {lfsr_out[3:0], feedback};
end

endmodule
